CODE_EXAMPLE:
// Error handling is the only concern of this function
public void processOrder(Order order) {
    try {
        processOrderHappyPath(order);
    } catch (Exception e) {
        handleOrderError(e);
    }
}

private void processOrderHappyPath(Order order) throws Exception {
    validate(order);
    save(order);
    notify(order);
    logger.log("saved");
}

private void handleOrderError(Exception e) {
    logger.log("failed: " + e.getMessage());
    metrics.increment("order.error");
}

